import React, { useState } from 'react';
import Header from './components/Header';
import LoadingSpinner from './components/LoadingSpinner';
import AnalysisDisplay from './components/AnalysisDisplay';
import { analyzeClothingImage } from './services/geminiService';
import { FashionAnalysis } from './types';
import { Camera, Upload, Image as ImageIcon } from 'lucide-react';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<FashionAnalysis | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Reset previous states
    setError(null);
    setAnalysis(null);
    setLoading(true);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        setImage(base64String);

        // Extract base64 data and mime type
        // result looks like: "data:image/jpeg;base64,/9j/4AAQ..."
        const base64Data = base64String.split(',')[1];
        const mimeType = base64String.split(';')[0].split(':')[1];

        try {
          const result = await analyzeClothingImage(base64Data, mimeType);
          setAnalysis(result);
        } catch (apiError) {
          setError("Analiz sırasında bir hata oluştu. Lütfen tekrar deneyin.");
          console.error(apiError);
        } finally {
          setLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Dosya okunamadı.");
      setLoading(false);
    }
  };

  const handleReset = () => {
    setImage(null);
    setAnalysis(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 pb-10">
      <Header />

      <main className="max-w-md mx-auto pt-6">

        {/* Intro Section - Only show when no image is selected */}
        {!image && !loading && (
          <div className="px-6 flex flex-col items-center text-center mt-8 animate-fade-in">
             <div className="w-20 h-20 bg-purple-100 rounded-full flex items-center justify-center mb-6 shadow-inner">
                <span className="text-4xl">👗</span>
             </div>
             <h2 className="text-2xl font-bold text-gray-800 mb-2">Stilini Keşfet</h2>
             <p className="text-gray-500 mb-8 leading-relaxed">
               Kıyafetinin fotoğrafını yükle, yapay zeka anında kumaşını analiz etsin ve sana özel harika kombinler önersin.
             </p>

             {/* Upload Buttons */}
             <div className="w-full space-y-4">
                <label className="w-full flex items-center justify-center space-x-3 bg-purple-600 text-white p-4 rounded-xl cursor-pointer hover:bg-purple-700 transition shadow-lg shadow-purple-200 active:scale-95">
                  <Camera className="w-6 h-6" />
                  <span className="font-semibold text-lg">Fotoğraf Çek</span>
                  <input type="file" accept="image/*" capture="environment" onChange={handleFileChange} className="hidden" />
                </label>

                <label className="w-full flex items-center justify-center space-x-3 bg-white text-gray-700 border border-gray-200 p-4 rounded-xl cursor-pointer hover:bg-gray-50 transition active:scale-95">
                  <ImageIcon className="w-6 h-6 text-gray-400" />
                  <span className="font-semibold text-lg">Galeriden Seç</span>
                  <input type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                </label>
             </div>

             <div className="mt-12 grid grid-cols-3 gap-4 w-full">
                <div className="text-center">
                    <div className="bg-white p-3 rounded-lg shadow-sm mb-2 mx-auto w-12 h-12 flex items-center justify-center">🎨</div>
                    <span className="text-xs font-medium text-gray-500">Renk Analizi</span>
                </div>
                <div className="text-center">
                    <div className="bg-white p-3 rounded-lg shadow-sm mb-2 mx-auto w-12 h-12 flex items-center justify-center">✨</div>
                    <span className="text-xs font-medium text-gray-500">Stil Önerisi</span>
                </div>
                <div className="text-center">
                    <div className="bg-white p-3 rounded-lg shadow-sm mb-2 mx-auto w-12 h-12 flex items-center justify-center">📍</div>
                    <span className="text-xs font-medium text-gray-500">Ortam Bilgisi</span>
                </div>
             </div>
