import React, { useState, useRef } from 'react';
import Header from './components/Header';
import LoadingSpinner from './components/LoadingSpinner';
import AnalysisDisplay from './components/AnalysisDisplay';
import BottomNavigation from './components/BottomNavigation';
import HomeView from './components/HomeView';
import ProfileView from './components/ProfileView';
import { analyzeClothingImage } from './services/geminiService';
import { FashionAnalysis } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'profile'>('home');
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<FashionAnalysis | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // References for hidden inputs
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Reset previous states and prepare for analysis
    setError(null);
    setAnalysis(null);
    setLoading(true);

    // Ensure we are viewing the "analysis" state effectively
    // (By virtue of `loading` or `image` being set, the view will switch)

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        setImage(base64String);

        const base64Data = base64String.split(',')[1];
        const mimeType = base64String.split(';')[0].split(':')[1];

        try {
          const result = await analyzeClothingImage(base64Data, mimeType);
          setAnalysis(result);
        } catch (apiError) {
          setError("Analiz sırasında bir hata oluştu. Lütfen tekrar deneyin.");
          console.error(apiError);
        } finally {
          setLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Dosya okunamadı.");
      setLoading(false);
    }

    // Reset inputs so same file can be selected again if needed
    if (event.target) event.target.value = '';
  };

  const handleReset = () => {
    setImage(null);
    setAnalysis(null);
    setError(null);
    setActiveTab('home'); // Go back to home when closing analysis
  };

  const triggerCamera = () => {
    cameraInputRef.current?.click();
  };

  const triggerGallery = () => {
    fileInputRef.current?.click();
  };

  // Logic to determine what content to render
  const renderContent = () => {
    if (loading) {
      return (
        <div className="mt-20">
          <LoadingSpinner />
        </div>
      );
    }

    if (image && analysis) {
      return (
        <AnalysisDisplay 
          data={analysis} 
          imageSrc={image} 
          onReset={handleReset} 
        />
      );
    }

    if (error) {
       return (
         <div className="p-6 text-center mt-10">
            <div className="bg-red-50 text-red-600 p-4 rounded-xl mb-4 border border-red-100">
              {error}
            </div>
            <button 
              onClick={handleReset}
              className="text-gray-600 font-medium underline"
            >
              Ana Sayfaya Dön
            </button>
         </div>
       );
    }

    if (activeTab === 'profile') {
      return <ProfileView />;
    }

    // Default to HomeView
    return <HomeView onCameraClick={triggerCamera} onGalleryClick={triggerGallery} />;
  };

  // If analysis is showing, we might hide the bottom nav or keep it. 
  // Standard mobile UX: Modal screens (like analysis result) cover the nav.
  const isAnalysisMode = (image || loading) && !error;

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 pb-20">
      <Header />

      <main className="max-w-md mx-auto pt-4">
        {renderContent()}
      </main>

      {/* Hidden Inputs */}
      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={cameraInputRef}
        onChange={handleFileChange} 
        className="hidden" 
      />
      <input 
        type="file" 
        accept="image/*" 
        ref={fileInputRef}
        onChange={handleFileChange} 
        className="hidden" 
      />

      {/* Only show bottom nav if NOT in analysis/loading mode */}
      {!isAnalysisMode && (
        <BottomNavigation 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onScanClick={triggerCamera}
        />
      )}
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { X, Camera } from 'lucide-react';

interface CameraViewProps {
  onCapture: (base64: string) => void;
  onClose: () => void;
}

const CameraView: React.FC<CameraViewProps> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
      try {
        // Request camera with preference for the rear camera (environment)
        stream = await navigator.mediaDevices.getUserMedia({
          video: { 
            facingMode: 'environment',
            width: { ideal: 1920 },
            height: { ideal: 1080 } 
          },
          audio: false
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Camera access denied:", err);
        setError("Kameraya erişim sağlanamadı. Lütfen tarayıcı izinlerini kontrol edin veya 'Galeriden Seç' seçeneğini kullanın.");
      }
    };

    startCamera();

    // Cleanup function to stop the stream when component unmounts
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleCapture = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      // Set canvas dimensions to match the video stream
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        // Draw the video frame to the canvas
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        // Convert to base64 JPEG
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);

        // Pass the image data back to the app
        onCapture(dataUrl);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col animate-fade-in">
      {/* Top Bar */}
      <div className="absolute top-0 left-0 right-0 p-6 z-20 flex justify-between items-center bg-gradient-to-b from-black/60 to-transparent">
        <button 
          onClick={onClose} 
          className="text-white bg-white/20 backdrop-blur-md p-2 rounded-full hover:bg-white/30 transition"
        >
          <X className="w-6 h-6" />
        </button>
        <span className="text-white font-medium drop-shadow-md">Fotoğraf Çek</span>
        <div className="w-10"></div> {/* Spacer for centering */}
      </div>

      {/* Video Preview */}
      <div className="flex-1 relative flex items-center justify-center bg-black overflow-hidden">
        {error ? (
          <div className="text-white text-center p-8 max-w-sm">
            <div className="bg-red-500/20 text-red-200 p-4 rounded-xl mb-6 backdrop-blur-sm">
               <Camera className="w-8 h-8 mx-auto mb-2 text-red-400" />
               <p>{error}</p>
            </div>
            <button onClick={onClose} className="bg-white text-gray-900 px-6 py-3 rounded-xl font-bold w-full">
              Geri Dön
            </button>
          </div>
        ) : (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            muted
            className="w-full h-full object-cover"
          />
        )}
      </div>

      {/* Bottom Controls */}
      {!error && (
        <div className="absolute bottom-0 left-0 right-0 h-40 bg-gradient-to-t from-black/80 to-transparent flex items-center justify-center pb-10">
          <div className="relative group">
             {/* Shutter Button Ring */}
             <div className="absolute inset-0 rounded-full border-4 border-white opacity-50 scale-110 group-active:scale-100 transition-transform duration-200"></div>

             {/* Shutter Button */}
             <button 
                onClick={handleCapture}
                className="w-20 h-20 bg-white rounded-full border-4 border-transparent shadow-lg active:scale-90 transition-transform duration-150 flex items-center justify-center relative z-10"
             >
                <div className="w-16 h-16 rounded-full border-2 border-gray-300"></div>
             </button>
          </div>
        </div>
      )}

      {/* Hidden Canvas */}
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default CameraView;

import React, { useState, useRef } from 'react';
import Header from './components/Header';
