import React, { useState, useRef } from 'react';
import Header from './components/Header';
import LoadingSpinner from './components/LoadingSpinner';
import { AnalysisDisplay } from './components/AnalysisDisplay';
import BottomNavigation from './components/BottomNavigation';
import HomeView from './components/HomeView';
import ProfileView from './components/ProfileView';
import CameraView from './components/CameraView';
import { analyzeClothingImage } from './services/geminiService';
import { FashionAnalysis } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'profile'>('home');
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<FashionAnalysis | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [showCamera, setShowCamera] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to save to local storage
  const saveToWardrobe = (img: string, data: FashionAnalysis) => {
    try {
      const newItem = {
        image: img,
        analysis: data,
        date: new Date().toISOString()
      };

      const existing = localStorage.getItem('stilai_wardrobe');
      const items = existing ? JSON.parse(existing) : [];

      // Limit to last 20 items to save space
      const updated = [...items, newItem].slice(-20);

      localStorage.setItem('stilai_wardrobe', JSON.stringify(updated));
    } catch (e) {
      console.error("Storage limit reached or error saving");
    }
  };

  const performAnalysis = async (base64String: string) => {
    setImage(base64String);
    setError(null);
    setAnalysis(null);
    setLoading(true);

    try {
      const base64Data = base64String.split(',')[1];
      const mimeType = base64String.split(';')[0].split(':')[1];
      const result = await analyzeClothingImage(base64Data, mimeType);

      setAnalysis(result);

      // Save valid results to wardrobe automatically if no error
      if (!result.hata) {
        saveToWardrobe(base64String, result);
      }

    } catch (apiError) {
      setError("Analiz sırasında bir hata oluştu. Lütfen tekrar deneyin.");
      console.error(apiError);
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        performAnalysis(base64String);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Dosya okunamadı.");
      setLoading(false);
    }

    if (event.target) event.target.value = '';
  };

  const handleCameraCapture = (base64String: string) => {
    setShowCamera(false);
    performAnalysis(base64String);
  };

  const handleReset = () => {
    setImage(null);
    setAnalysis(null);
    setError(null);
    setActiveTab('home');
  };

  const triggerCamera = () => {
    setShowCamera(true);
  };

  const triggerGallery = () => {
    fileInputRef.current?.click();
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="mt-20">
          <LoadingSpinner />
        </div>
      );
    }

    if (image && analysis) {
      return (
        <AnalysisDisplay 
          data={analysis} 
          imageSrc={image} 
          onReset={handleReset} 
        />
      );
    }

    if (error) {
       return (
         <div className="p-6 text-center mt-10">
            <div className="bg-red-50 text-red-600 p-4 rounded-xl mb-4 border border-red-100">
              {error}
            </div>
            <button 
              onClick={handleReset}
              className="text-gray-600 font-medium underline"
            >
              Ana Sayfaya Dön
            </button>
         </div>
       );
    }

    if (activeTab === 'profile') {
      return <ProfileView />;
    }

    return <HomeView onCameraClick={triggerCamera} onGalleryClick={triggerGallery} />;
  };

  const isAnalysisMode = (image || loading) && !error;

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 pb-20">
      <Header />

      <main className="max-w-md mx-auto pt-4">
        {renderContent()}
      </main>

      {showCamera && (
        <CameraView 
          onCapture={handleCameraCapture} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <input 
        type="file" 
        accept="image/*" 
        ref={fileInputRef}
        onChange={handleFileChange} 
        className="hidden" 
      />

      {!isAnalysisMode && !showCamera && (
        <BottomNavigation 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onScanClick={triggerCamera}
        />
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { FashionAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Define the schema for the JSON response to ensure type safety from the model
const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    parca_analizi: { type: Type.STRING, description: "Kıyafetin türü, rengi, deseni ve kumaş analizi." },
    kombin_onerisi: { type: Type.STRING, description: "Alt giyim, dış giyim önerileri." },
    ortam: { type: Type.STRING, description: "Bu kıyafetin uygun olduğu senaryolar." },
    aksesuar_ayakkabi: { type: Type.STRING, description: "Tamamlayıcı aksesuar ve ayakkabı önerileri." },
    stil_puani: { type: Type.INTEGER, description: "1 ile 10 arasında bir puan." },
    uzman_tuyosu: { type: Type.STRING, description: "Kısa bir stil ipucu." },
    hata: { type: Type.STRING, description: "Eğer görselde kıyafet yoksa hata mesajı.", nullable: true }
  },
  required: ["parca_analizi", "kombin_onerisi", "ortam", "aksesuar_ayakkabi", "stil_puani", "uzman_tuyosu"],
};

export const analyzeClothingImage = async (base64Image: string, mimeType: string): Promise<FashionAnalysis> => {
  try {
    const model = "gemini-3-flash-preview";

    const prompt = `
    Sen profesyonel bir "AI Moda Danışmanı" ve "Görsel Stil Analiz Uzmanı"sın.
    Görevlerin:
    1. Görseli analiz et (tür, renk, desen, kumaş).
    2. Kombin önerisi yap.
    3. Kullanım alanını belirt.
    4. Mobil uyumlu, emoji içeren kısa yanıtlar ver.
    5. 1-10 arası puan ver.

    Eğer görselde bir kıyafet yoksa, "hata" alanını doldur.
    Yanıtı SADECE geçerli bir JSON objesi olarak ver.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        systemInstruction: "Sen Türk kültürüne ve modern moda trendlerine hakim, nazik ve yapıcı bir moda danışmanısın.",
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const parsedResponse = JSON.parse(text) as FashionAnalysis;
    return parsedResponse;

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const askStylist = async (
  question: string, 
  previousContext: FashionAnalysis
): Promise<string> => {
  try {
    const model = "gemini-3-flash-preview";

    const contextPrompt = `
      Önceki analiz verileri:
      - Parça: ${previousContext.parca_analizi}
      - Mevcut Öneri: ${previousContext.kombin_onerisi}
      - Ortam: ${previousContext.ortam}

      Kullanıcı bu analiz üzerine şu soruyu soruyor: "${question}"

      Kısa, samimi ve uzman bir moda danışmanı gibi cevap ver. 2-3 cümleyi geçme. Emoji kullan.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [{ text: contextPrompt }]
      },
      config: {
        systemInstruction: "Sen kullanıcıyla sohbet eden bir stil danışmanısın. Yardımcı ve pozitif ol.",
      }
    });

    return response.text || "Şu an cevap veremiyorum, lütfen tekrar dene.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Bağlantıda bir sorun oluştu.";
  }
};

