import React, { useEffect, useState } from 'react';
import { Camera, Image as ImageIcon, Sparkles, ArrowRight, Sun, Moon, Zap, TrendingUp, Palette, Umbrella, Newspaper, Globe, Loader2, RefreshCw } from 'lucide-react';
