import React, { useState } from 'react';
import { Shirt, ArrowRight, Sparkles, Mail, Lock, User, Loader2 } from 'lucide-react';
import { UserProfile } from '../types';

interface AuthViewProps {
  onLogin: (user: UserProfile) => void;
}

const AuthView: React.FC<AuthViewProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Simulate API delay
    setTimeout(() => {
      try {
        const usersStr = localStorage.getItem('stilai_users_db');
        const users: UserProfile[] = usersStr ? JSON.parse(usersStr) : [];

        if (isLogin) {
          // LOGIN LOGIC
          const user = users.find(u => u.email === formData.email && u.password === formData.password);
          if (user) {
            onLogin(user);
          } else {
            setError("E-posta veya şifre hatalı.");
          }
        } else {
          // REGISTER LOGIC
          if (!formData.name || !formData.email || !formData.password) {
            setError("Lütfen tüm alanları doldurun.");
            setLoading(false);
            return;
          }

          if (users.find(u => u.email === formData.email)) {
            setError("Bu e-posta adresi zaten kayıtlı.");
            setLoading(false);
            return;
          }

          const newUser: UserProfile = {
            id: Date.now().toString(),
            name: formData.name,
            email: formData.email,
            password: formData.password,
            joinDate: new Date().toISOString()
          };

          users.push(newUser);
          localStorage.setItem('stilai_users_db', JSON.stringify(users));
          onLogin(newUser);
        }
      } catch (err) {
        setError("Bir hata oluştu. Lütfen tekrar deneyin.");
      } finally {
        setLoading(false);
      }
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-white flex flex-col justify-center px-6 animate-fade-in relative overflow-hidden">

      {/* Background Decor */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-purple-100 rounded-full blur-3xl opacity-50 -mr-20 -mt-20"></div>
      <div className="absolute bottom-0 left-0 w-64 h-64 bg-indigo-100 rounded-full blur-3xl opacity-50 -ml-20 -mb-20"></div>

      <div className="relative z-10 max-w-md mx-auto w-full">
        {/* Header Logo Area */}
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-tr from-purple-600 to-indigo-600 rounded-2xl shadow-lg shadow-purple-200 mb-4 transform rotate-3">
            <Shirt className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight">
            Stil<span className="text-purple-600">AI</span>
          </h1>
          <p className="text-gray-500 mt-2 text-sm">Yapay Zeka Destekli Moda Asistanın</p>
        </div>

        {/* Form Container */}
        <div className="bg-white/80 backdrop-blur-xl border border-white shadow-xl rounded-3xl p-8 relative">

           <h2 className="text-xl font-bold text-gray-800 mb-6 text-center">
             {isLogin ? 'Tekrar Hoşgeldin!' : 'Stil Yolculuğuna Başla'}
           </h2>

           {error && (
             <div className="mb-4 p-3 bg-red-50 text-red-600 text-xs rounded-xl border border-red-100 text-center">
               {error}
             </div>
           )}

           <form onSubmit={handleSubmit} className="space-y-4">
             {!isLogin && (
               <div className="relative group">
                 <User className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 group-focus-within:text-purple-600 transition-colors" />
                 <input
                   type="text"
                   name="name"
                   placeholder="Adın Soyadın"
                   value={formData.name}
                   onChange={handleChange}
                   className="w-full bg-gray-50 border border-gray-200 rounded-xl py-3 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/50 focus:border-purple-500 transition-all"
                 />
               </div>
             )}

             <div className="relative group">
               <Mail className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 group-focus-within:text-purple-600 transition-colors" />
               <input
                 type="email"
                 name="email"
                 placeholder="E-posta Adresin"
                 value={formData.email}
                 onChange={handleChange}
                 className="w-full bg-gray-50 border border-gray-200 rounded-xl py-3 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/50 focus:border-purple-500 transition-all"
               />
             </div>

             <div className="relative group">
               <Lock className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 group-focus-within:text-purple-600 transition-colors" />
               <input
                 type="password"
                 name="password"
                 placeholder="Şifren"
                 value={formData.password}
                 onChange={handleChange}
                 className="w-full bg-gray-50 border border-gray-200 rounded-xl py-3 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/50 focus:border-purple-500 transition-all"
               />
             </div>

             <button
               type="submit"
               disabled={loading}
               className="w-full bg-gray-900 text-white py-3.5 rounded-xl font-bold text-sm hover:bg-gray-800 transition-all shadow-lg shadow-gray-200 flex items-center justify-center space-x-2 mt-2"
             >
               {loading ? (
                 <Loader2 className="w-5 h-5 animate-spin" />
               ) : (
                 <>
                   <span>{isLogin ? 'Giriş Yap' : 'Hesap Oluştur'}</span>
                   <ArrowRight className="w-4 h-4" />
                 </>
               )}
             </button>
           </form>

           <div className="mt-6 text-center">
             <button
               onClick={() => { setIsLogin(!isLogin); setError(null); }}
               className="text-xs text-gray-500 hover:text-purple-600 font-medium transition-colors"
             >
               {isLogin ? "Hesabın yok mu? Kayıt Ol" : "Zaten hesabın var mı? Giriş Yap"}
             </button>
           </div>
        </div>

        <div className="mt-8 flex justify-center space-x-2 text-[10px] text-gray-400">
           <Sparkles className="w-3 h-3" />
           <span>Kişiselleştirilmiş Moda Deneyimi</span>
           <Sparkles className="w-3 h-3" />
        </div>
      </div>
    </div>
  );
};

export default AuthView;

import React, { useEffect, useState, useRef } from 'react';
import { Settings, Heart, ChevronRight, Calendar, Trash2, ArrowLeft, Bell, Shield, HelpCircle, Moon, Globe, LogOut, Award, Filter, UserCircle, Check, Camera, Edit2 } from 'lucide-react';
import { StoredItem, UserPreferences, UserProfile } from '../types';

interface ProfileViewProps {
  user: UserProfile | null;
  onLogout: () => void;
  onUpdateUser: (user: UserProfile) => void;
}

const ProfileView: React.FC<ProfileViewProps> = ({ user, onLogout, onUpdateUser }) => {
  const [history, setHistory] = useState<StoredItem[]>([]);
  const [viewMode, setViewMode] = useState<'all' | 'favorites' | 'settings'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [notificationsEnabled, setNotificationsEnabled] = useState(true);

  // Preference States
  const [preferences, setPreferences] = useState<UserPreferences>({
    bodyType: 'Belirtilmemiş',
    styleGoal: 'Belirtilmemiş',
    gender: 'Kadın'
  });
  const [showSaveSuccess, setShowSaveSuccess] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const CATEGORIES = [
      { id: 'all', label: 'Tümü' },
      { id: 'fav', label: 'Favoriler' },
      { id: 'Üst Giyim', label: 'Üst Giyim' },
      { id: 'Alt Giyim', label: 'Alt Giyim' },
      { id: 'Elbise', label: 'Elbise' },
      { id: 'Dış Giyim', label: 'Dış Giyim' },
      { id: 'Ayakkabı', label: 'Ayakkabı' }
  ];

  useEffect(() => {
    loadHistory();
    loadPreferences();
  }, []);

  const loadHistory = () => {
    const stored = localStorage.getItem('stilai_wardrobe');
    if (stored) {
      try {
        setHistory(JSON.parse(stored).reverse()); // Show newest first
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  };

  const loadPreferences = () => {
    const stored = localStorage.getItem('stilai_user_prefs');
    if (stored) {
      try {
        setPreferences(JSON.parse(stored));
      } catch (e) {}
    }
  };

  const savePreferences = () => {
    localStorage.setItem('stilai_user_prefs', JSON.stringify(preferences));
    setShowSaveSuccess(true);
    setTimeout(() => setShowSaveSuccess(false), 2000);
  };

  const handleClearData = () => {
    if(confirm("Tüm gardırop geçmişiniz ve kayıtlı analizleriniz silinecek. Bu işlem geri alınamaz. Devam etmek istiyor musunuz?")) {
      localStorage.removeItem('stilai_wardrobe');
      setHistory([]);
      alert("Tüm veriler başarıyla temizlendi.");
    }
  }

  const toggleFavorite = (id: string) => {
    const updatedHistory = history.map(item => {
      if (item.id === id) {
        return { ...item, isFavorite: !item.isFavorite };
      }
      return item;
    });

    // Save reversed back to storage (since history is displayed reversed)
    const storageOrder = [...updatedHistory].reverse();
    localStorage.setItem('stilai_wardrobe', JSON.stringify(storageOrder));
    setHistory(updatedHistory);
  };

  const handleAvatarClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && user) {
        const reader = new FileReader();
        reader.onloadend = () => {
            const base64 = reader.result as string;

            // Basic optimization/resizing logic (simplified)
            const img = new Image();
            img.src = base64;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                const MAX_SIZE = 300; // Small size for avatar
                let width = img.width;
                let height = img.height;

                if (width > height) {
                    if (width > MAX_SIZE) {
                        height *= MAX_SIZE / width;
                        width = MAX_SIZE;
                    }
                } else {
                    if (height > MAX_SIZE) {
                        width *= MAX_SIZE / height;
                        height = MAX_SIZE;
                    }
                }
                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, width, height);
                const resizedBase64 = canvas.toDataURL('image/jpeg', 0.8);

                // Update User
                const updatedUser = { ...user, avatar: resizedBase64 };
                onUpdateUser(updatedUser);
            }
        };
        reader.readAsDataURL(file);
    }
  };

  const averageScore = history.length > 0 
    ? (history.reduce((acc, curr) => acc + curr.analysis.stil_puani, 0) / history.length).toFixed(1) 
    : "0.0";

  const favoritesCount = history.filter(h => h.isFavorite).length;

  // Complex Filtering Logic
  const getFilteredItems = () => {
      if (viewMode === 'favorites') return history.filter(i => i.isFavorite);

      let items = history;
      if (categoryFilter === 'fav') {
          items = items.filter(i => i.isFavorite);
      } else if (categoryFilter !== 'all') {
          items = items.filter(i => i.analysis.kategori === categoryFilter);
      }
      return items;
  }

  const displayedItems = getFilteredItems();

  return (
    <div className="px-5 pt-2 animate-fade-in pb-20">

      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />

      {/* Main Profile Header (Only show in main view) */}
      {viewMode === 'all' && (
        <>
          <div className="flex items-center space-x-4 mb-8">
            <div className="relative group cursor-pointer" onClick={handleAvatarClick}>
                <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-200 to-indigo-200 p-1 shadow-lg">
                    <div className="w-full h-full rounded-full bg-white flex items-center justify-center overflow-hidden relative">
                        {user?.avatar ? (
                            <img src={user.avatar} alt="Profile" className="w-full h-full object-cover" />
                        ) : (
                            <span className="text-3xl">😎</span>
                        )}
                        {/* Overlay on hover */}
                        <div className="absolute inset-0 bg-black/30 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                            <Camera className="w-6 h-6 text-white" />
                        </div>
                    </div>
                </div>
                <div className="absolute bottom-0 right-0 bg-purple-600 text-white p-1.5 rounded-full border-2 border-white shadow-sm">
                    <Edit2 className="w-3 h-3" />
                </div>
            </div>

            <div className="flex-1">
              <h2 className="text-xl font-bold text-gray-800">{user?.name || "Misafir Kullanıcı"}</h2>
              <p className="text-xs text-gray-500 mb-2">{user?.email}</p>
              <div className="flex items-center space-x-2">
                <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-0.5 rounded-full font-medium flex items-center">
                  <Award className="w-3 h-3 mr-1" />
                  Ortalama: {averageScore}
                </span>
                <span className="bg-purple-50 text-purple-600 text-xs px-2 py-0.5 rounded-full font-medium">
                   {preferences.styleGoal !== 'Belirtilmemiş' ? preferences.styleGoal : 'Stil Belirlenmedi'}
                </span>
              </div>
            </div>
          </div>

          {/* Stats Grid */}
          <div className="grid grid-cols-2 gap-3 mb-6">
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center justify-center text-center">
                <span className="text-2xl font-bold text-gray-800">{history.length}</span>
                <span className="text-xs text-gray-500 mt-1">Gardırop</span>
            </div>
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center justify-center text-center">
                <span className="text-2xl font-bold text-pink-500">{favoritesCount}</span>
                <span className="text-xs text-gray-500 mt-1">Favori Parça</span>
            </div>
          </div>
        </>
      )}

      {/* Header for Sub Views (Favorites or Settings) */}
      {viewMode !== 'all' && (
         <div className="flex items-center mb-6">
            <button 
              onClick={() => setViewMode('all')}
              className="p-2 -ml-2 hover:bg-gray-100 rounded-full transition"
            >
               <ArrowLeft className="w-5 h-5 text-gray-700" />
            </button>
            <h2 className="text-xl font-bold text-gray-800 ml-2">
              {viewMode === 'favorites' ? 'Favorilerim' : 'Ayarlar'}
            </h2>
         </div>
      )}

      {/* Main List & Menu (viewMode === 'all') */}
      {viewMode === 'all' && (
        <>
            {/* Menu Links (Compact) */}
            <div className="flex space-x-3 mb-6">
                 <button 
                    onClick={() => setViewMode('settings')}
